+func splitColumns(raw string) []string {
+	parts := strings.Split(raw, ",")
+	columns := make([]string, 0, len(parts))
+	for _, p := range parts {
+		col := strings.TrimSpace(strings.Trim(p, "`"))
+		if col != "" {
+			columns = append(columns, col)
+		}
+	}
+	return columns
